package com.careeros.watchlist.web; import com.careeros.watchlist.application.*; import com.careeros.watchlist.domain.*; import com.careeros.common.web.PageResponse; import jakarta.validation.constraints.*; import org.springframework.data.domain.*; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/watchlists") public class WatchlistController{private final WatchlistService s;public WatchlistController(WatchlistService s){this.s=s;}@PostMapping public Response create(@RequestBody Name r){return out(s.create(r.name));}@GetMapping public PageResponse<Response> list(Pageable p){return PageResponse.from(s.list(p),this::out);}@GetMapping("/{id}")public Response get(@PathVariable UUID id){return out(s.get(id));}@PutMapping("/{id}")public Response rename(@PathVariable UUID id,@RequestBody Name r){return out(s.rename(id,r.name));}@PutMapping("/{id}/companies/{companyId}")public Response add(@PathVariable UUID id,@PathVariable UUID companyId,@RequestBody Membership r){return out(s.add(id,companyId,r.priority,r.enabled));}@DeleteMapping("/{id}/companies/{companyId}")public Response remove(@PathVariable UUID id,@PathVariable UUID companyId){return out(s.remove(id,companyId));}@DeleteMapping("/{id}")@ResponseStatus(HttpStatus.NO_CONTENT)public void delete(@PathVariable UUID id){s.delete(id);}private Response out(Watchlist w){return new Response(w.getId(),w.getName(),w.getCompanies().stream().map(x->new CompanyItem(x.getCompany().getId(),x.getCompany().getName(),x.getPriority(),x.isEnabled())).toList());}public record Name(@NotBlank String name){}public record Membership(@Min(0)@Max(100)int priority,boolean enabled){}public record CompanyItem(UUID id,String name,int priority,boolean enabled){}public record Response(UUID id,String name,List<CompanyItem> companies){}}
